export async function POST(req: NextRequest) {
  const secret = req.headers.get("x-import-secret");
  if (secret !== SECRET) return NextResponse.json({ error: "Yetkisiz" }, { status: 401 });

  const results = { sahip: 0, sahiplik: 0, atlandı: 0, hatalar: [] as string[] };

  // 1. Etap konut haritası
  const konutlar = await prisma.konut.findMany({ where: { etap: 1 }, select: { id: true, daireNo: true } });
  const konutMap = new Map(konutlar.map(k => [k.daireNo, k.id]));

  // Sahipleri oluştur (key → id eşlemesi kur)
  const sahipIdMap = new Map<string, string>();
  for (const s of SAHIPLER) {
    try {
      let sahibiId: string | undefined;
      if (s.tip === "Kurumsal" && s.vergiNo) {
        const row = await prisma.daireSahibi.upsert({
          where: { vergiNo: s.vergiNo },
          create: {
            tip: "Kurumsal", vergiNo: s.vergiNo, unvan: s.unvan ?? null,
            ad: s.unvan ?? "Kurum", soyad: "-",
            telefon: s.telefon, email: s.email,
          },
          update: { tip: "Kurumsal", unvan: s.unvan ?? null },
        });
        sahibiId = row.id;
      } else if (s.tcKimlik) {
        const row = await prisma.daireSahibi.upsert({
          where: { tcKimlik: s.tcKimlik },
          create: {
            tip: "Bireysel", tcKimlik: s.tcKimlik,
            ad: s.ad, soyad: s.soyad,
            telefon: s.telefon, email: s.email,
          },
          update: { tip: "Bireysel", ad: s.ad, soyad: s.soyad },
        });
        sahibiId = row.id;
      } else {
        // TC yok & şirket değil → isim bazlı ara ya da oluştur
        const found = await prisma.daireSahibi.findFirst({
          where: { ad: s.ad, soyad: s.soyad, tcKimlik: null, vergiNo: null },
        });
        if (found) {
          sahibiId = found.id;
        } else {
          const row = await prisma.daireSahibi.create({
            data: { tip: "Bireysel", ad: s.ad, soyad: s.soyad, telefon: s.telefon, email: s.email },
          });
          sahibiId = row.id;
        }
      }
      if (sahibiId) sahipIdMap.set(s.key, sahibiId);
      results.sahip++;
    } catch (e) {
      results.hatalar.push(`Sahip hatası ${s.key}: ${e instanceof Error ? e.message : String(e)}`);
    }
  }

  // Sahiplik kayıtları
  for (const sh of SAHIPLIKLER) {
    const konutId = konutMap.get(sh.daireNo);
    if (!konutId) { results.hatalar.push(`Daire bulunamadı: ${sh.daireNo}`); continue; }
    const sahipId = sahipIdMap.get(sh.sahipKey);
    if (!sahipId) { results.hatalar.push(`Sahip yok: ${sh.sahipKey}`); continue; }
    try {
      // Aynı konut+sahip+tarih varsa geç
      const mevcut = await prisma.daireSahipligi.findFirst({
        where: { konutId, daireSahibiId: sahipId, alisTarihi: sh.alisTarihi ? new Date(sh.alisTarihi) : undefined },
      });
      if (mevcut) { results.atlandı++; continue; }
      await prisma.daireSahipligi.create({
        data: {
          konutId, daireSahibiId: sahipId,
          alisTarihi: sh.alisTarihi ? new Date(sh.alisTarihi) : new Date("2014-11-24"),
          ipotekli: sh.ipotekli,
          pay: sh.pay, payda: sh.payda,
        },
      });
      results.sahiplik++;
      // Aktif (satış yok) → konut.daireSahibiId güncelle (pay=1/1 ise)
      if (sh.payda === 1) {
        await prisma.konut.update({ where: { id: konutId }, data: { daireSahibiId: sahipId } });
      }
    } catch (e) {
      results.hatalar.push(`${sh.daireNo}: ${e instanceof Error ? e.message : String(e)}`);
    }
  }

  return NextResponse.json({ ok: true, ...results });
}
